form:Form.form:Scripts:
		function load()
{	
	// Setear fecha de hoy
	Ctrl('f_hoy').SetXValue(date2str(NowDate()));	

	// Validación, para que no se pueda modificar ni el Tipo de Evaluación, ni la Empresa, salvo en el caso de que se esté creando el Evento
	if (Ctrl('main').GetMode() != 'NEW') 
	{
		CtrlEnabled('c_clase_eval', false);
		CtrlEnabled('oi_empresa', false);
	}

	//Validación de botones en modo LIST y SHOW
	if (Ctrl('main').GetMode()=="LIST")
	{
		ChangeSelect();		
	}
	else
	{
		var estado = Ctrl('c_estado').GetXValue()
		SetStatus(estado);
	}	
}


function ChangeSelect()
{
	var estado = Ctrl('LIST').GetSelectAttrValue('c_estado');
	SetStatus(estado);		
}         

function SetStatus(estado)
{
	switch (estado)
	{
		case 'A':
			CtrlEnabled('ADMINISTRAR', true);				
			CtrlEnabled('cerrar', false);
			CtrlEnabled('EDIT', true);
			CtrlEnabled('DELETE', true);
		break;

		case 'I':                         
			CtrlEnabled('ADMINISTRAR', true);				
			CtrlEnabled('cerrar', true);
			CtrlEnabled('EDIT', true);
			CtrlEnabled('DELETE', false);		
		break;

		case 'C':                        
			CtrlEnabled('ADMINISTRAR', false);				
			CtrlEnabled('cerrar', false);
			CtrlEnabled('EDIT', false);
			CtrlEnabled('DELETE', false);		
		break;
	}				

}
